      value.output,
      value.result,
      value.text,
      value.data,
      value.message?.content,
      value.choices?.[0]?.message?.content,
      value.choices?.[0]?.text,
    ];

    for (const candidate of nestedCandidates) {
      const nested = tryExtractFiles(candidate, seen, depth + 1);
      if (nested) return nested;
    }
  }

  return null;
}

function recoverReadmeFileOnly(files, rawModelText) {
  const current = Array.isArray(files) ? files.slice() : [];
  if (current.some((entry) => entry && entry.path === 'backend/README.md')) {
    return current;
  }

  function extractReadmeContentFromText(sourceText) {
    const text = String(sourceText || '');
    if (!text) return '';

    const markerRegex = /"path"\s*:\s*"backend\/README\.md"\s*,\s*"content"\s*:\s*"/g;
    const markerMatch = markerRegex.exec(text);
    if (!markerMatch) return '';

    let index = markerMatch.index + markerMatch[0].length;
    let escaped = false;
    let content = '';

    while (index < text.length) {
      const ch = text[index];

      if (escaped) {
        content += '\\' + ch;
        escaped = false;
        index += 1;
        continue;
      }

      if (ch === '\\') {
        escaped = true;
        index += 1;
        continue;
      }

      if (ch === '"') {
        const tail = text.slice(index + 1);
        if (/^\s*[,}]/.test(tail)) {
          break;
        }
      }

      content += ch;
      index += 1;
    }

    const normalized = unescapeLiteralText(content)
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .replace(/^\s+/, '')
      .trimEnd();

    if (!normalized) return '';
    if (!normalized.startsWith('#')) return '';
    if (normalized.length < 40) return '';
    return normalized;
  }

  const candidates = [];
  if (typeof rawModelText === 'string' && rawModelText.trim()) {
    candidates.push(rawModelText);
    const normalized = normalizeStreamingText(rawModelText);
    if (normalized && normalized !== rawModelText) {
      candidates.push(normalized);
    }
  }

  for (const candidate of candidates) {
    const readmeContent = extractReadmeContentFromText(candidate);
    if (!readmeContent) continue;
    current.push({ path: 'backend/README.md', content: readmeContent });
    break;
  }

  return current;
}
function extractBackendFiles(rawModelText, rootJson) {
  const orderedCandidates = [
    rawModelText,
    rootJson,
    rootJson?.data,
    rootJson?.response,
    rootJson?.output,
    rootJson?.result,
    rootJson?.text,
  ];

  for (const candidate of orderedCandidates) {
    const files = tryExtractFiles(candidate);
    if (files && files.length) return recoverReadmeFileOnly(files, rawModelText);
  }

  throw new Error('Could not extract backend files from model output.');
}

