function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  const normalized = [];
  const seen = new Set();

  for (const entry of files) {
    const candidatePath = typeof entry === 'string'
      ? entry
      : (entry && typeof entry === 'object' ? String(entry.path ?? '') : '');

    const rawPath = String(candidatePath || '').trim().replace(/\\/g, '/');
    if (!rawPath) continue;

    const prefixedPath = rawPath.startsWith('backend/')
      ? rawPath
      : `backend/${rawPath.replace(/^\/+/, '')}`;
    const path = prefixedPath.replace(/\/+/g, '/');

    const hasTraversal = (
      path.includes('/../')
      || path.startsWith('../')
      || path.endsWith('/..')
      || path.includes('/./')
      || path.startsWith('backend/../')
      || path.includes(':')
      || path.endsWith('/')
    );
    if (hasTraversal) continue;

    const blockedPrefixes = [
      'backend/main/',
      'backend/target/',
      'backend/node_modules/',
      'backend/.git/',
      'backend/.idea/',
      'backend/.vscode/',
      'backend/.DS_Store',
    ];
    if (blockedPrefixes.some((prefix) => path.startsWith(prefix) || path === prefix.replace(/\/$/, ''))) {
      continue;
    }

    if (!path.startsWith('backend/')) continue;

    if (seen.has(path)) continue;
    seen.add(path);
    normalized.push({ path });
  }

  return normalized;
}

