function getExtension(filePath) {
  const fileName = String(filePath || '').split('/').pop() || '';
  if (fileName === 'pom.xml') return 'xml';
  if (fileName === '.gitignore') return 'gitignore';
  const match = fileName.match(/\.([A-Za-z0-9]+)$/);
  return match ? match[1].toLowerCase() : 'txt';
}

function getMimeType(filePath) {
  const ext = getExtension(filePath);
  const mimeByExtension = {
    java: 'text/x-java-source',
    xml: 'application/xml',
    yaml: 'text/yaml',
    yml: 'text/yaml',
    json: 'application/json',
    properties: 'text/plain',
    md: 'text/markdown',
    txt: 'text/plain',
    sql: 'application/sql',
    csv: 'text/csv',
    js: 'text/javascript',
    ts: 'text/plain',
    html: 'text/html',
    css: 'text/css',
    gitignore: 'text/plain',
  };
  return mimeByExtension[ext] || 'text/plain';
}

function normalizeFiles(value) {
  const files = Array.isArray(value) ? value : [];
  const normalized = [];

  for (const entry of files) {
    if (!entry || typeof entry !== 'object') continue;
    const rawPath = String(entry.path ?? '').trim().replace(/\\/g, '/');
    if (!rawPath) continue;

    const prefixedPath = rawPath.startsWith('backend/')
      ? rawPath
      : `backend/${rawPath.replace(/^\/+/, '')}`;
    const path = prefixedPath.replace(/\/+/g, '/');

    const hasTraversal = (
      path.includes('/../')
      || path.startsWith('../')
      || path.endsWith('/..')
      || path.includes('/./')
      || path.startsWith('backend/../')
      || path.includes(':')
      || path.endsWith('/')
    );
    if (hasTraversal) continue;

    const blockedPrefixes = [
      'backend/main/',
      'backend/target/',
      'backend/node_modules/',
      'backend/.git/',
      'backend/.idea/',
      'backend/.vscode/',
      'backend/.DS_Store',
    ];
    if (blockedPrefixes.some((prefix) => path.startsWith(prefix) || path === prefix.replace(/\/$/, ''))) {
      continue;
    }

    if (!path.startsWith('backend/')) continue;

    let content = '';
    if (typeof entry.content === 'string') content = entry.content;
    else if (entry.content === null || typeof entry.content === 'undefined') content = '';
    else if (typeof entry.content === 'object') content = JSON.stringify(entry.content, null, 2);
    else content = String(entry.content);

    normalized.push({ path, content });
  }

  return normalized;
}

